+bool AutoUpdater::ValidateUpdatePackageContents(
+    const base::DictionaryValue& update_info) {
+  // Check for presence of components array in update info
+  const base::Value* components = update_info.FindKey("components");
+  if (!components) {
+    // No components to validate - this is valid for simple updates
+    return true;
+  }
+
+  if (!components->is_list()) {
+    LOG(ERROR) << "Components field must be an array";
+    return false;
+  }
+
+  // Validate each component has proper signature information
+  const auto& components_list = components->GetList();
+  for (const auto& component : components_list) {
+    if (!ValidateComponentSignature(component)) {
+      return false;
+    }
+  }
+
+  return true;
+}
+
+bool AutoUpdater::ValidateComponentSignature(const base::Value& component) {
+  // Verify that the component has valid signature information
+  // and that the signature covers the entire component content
+  if (!component.is_dict()) {
+    LOG(ERROR) << "Component must be a dictionary";
+    return false;
+  }
+
+  const base::DictionaryValue* component_dict;
+  if (!component.GetAsDictionary(&component_dict)) {
+    return false;
+  }
+
+  // Check for required signature fields
+  if (!component_dict->HasKey("signature") || !component_dict->HasKey("sha256")) {
+    LOG(ERROR) << "Component missing required signature fields";
+    return false;
+  }
+
+  return true;
+}
