@@ -0,0 +1,25 @@
+'use strict';
+
+var MAX_PATTERN_LENGTH = 1000;
+
+module.exports = {
+  checkPattern: function(pattern) {
+    if (typeof pattern !== 'string') return;
+    
+    if (pattern.length > MAX_PATTERN_LENGTH) {
+      throw new Error('Invalid pattern: pattern too long (max ' + MAX_PATTERN_LENGTH + ' characters)');
+    }
+    
+    // Check for potentially dangerous regex patterns that can cause catastrophic backtracking
+    // Patterns with nested quantifiers like (a+)+ or (a|a)* are common ReDoS vectors
+    var dangerousPatterns = [
+      /\([^)]*\+[^)]*\)\+/,  // Nested quantifiers: (a+)+
+      /\([^)]*\*[^)]*\)\*/,  // Nested quantifiers: (a*)*
+      /\([^)]*\?[^)]*\)\?/,  // Nested quantifiers: (a?)?
+      /\(\.[^)]*\)\+/,       // Dot inside group with quantifier
+      /\(\|[^)]*\)\+/,       // Alternation with quantifier
+    ];
+    
+    for (var i = 0; i < dangerousPatterns.length; i++) {
+      if (dangerousPatterns[i].test(pattern)) {
+        throw new Error('Invalid pattern: potentially dangerous regex pattern detected');
+      }
+    }
+  }
+};

